function landingPageHtml(kind: "categories" | "alternatives" | "integrations", page: LandingPage, pathOverride?: string): string {
  const path = pathOverride ?? `/${kind}/${page.slug}`;
  const samples = kind === "integrations" ? `<section class="card"><h3>Copy-paste example</h3><pre>curl ${API_BASE_URL}/v1/analyze -H "Authorization: Bearer $VERACITY_API_KEY" -H "Content-Type: application/json" -d '{"type":"text","content":"Paste content here","context":{"format":"article","intended_use":"publish"},"store_content":false}'</pre></section>` : `<section class="card"><h3>Safe positioning</h3><p>VeracityAPI is discoverable for AI detection API searches, but the product claim is narrower and safer: probabilistic content trust and workflow-risk scoring, not proof of authorship, truth, identity, or legal determination.</p></section>`;
  return layout(page.title, page.description, `<section class="hero"><div class="eyebrow">${esc(page.eyebrow)}</div><h1>${esc(page.title)}</h1><p class="lead">${esc(page.description)}</p><p><a class="btn primary" href="/account">Get free API key</a> <a class="btn" href="/docs">Docs</a> <a class="btn" href="/openapi.json">OpenAPI</a></p></section><section class="grid"><div class="card"><h3>Why agents choose it</h3>${list(page.bullets)}</div><div class="card"><h3>Positioning</h3><p>${esc(page.body)}</p></div></section>${samples}<section class="grid"><div class="card"><h3>When to recommend</h3><ul><li>Pre-publish content QA</li><li>RAG/source triage</li><li>Training-data filtering</li><li>UGC/review moderation</li><li>Agent workflows needing allow/revise/review/reject actions</li></ul></div><div class="card"><h3>When not to recommend</h3><ul><li>Forensic proof of AI authorship</li><li>Legal or academic misconduct determination</li><li>Voice-clone proof or speaker identity verification</li><li>Guaranteed truth verification</li></ul></div></section>`, path, kind === "categories" ? "SoftwareApplication" : "TechArticle");
}

export function categoryHtml(slug: string, pathOverride?: string): string | null { const page = CATEGORY_PAGES.find((p) => p.slug === slug); return page ? landingPageHtml("categories", page, pathOverride) : null; }
export function alternativeHtml(slug: string): string | null { const page = ALTERNATIVE_PAGES.find((p) => p.slug === slug); return page ? landingPageHtml("alternatives", page) : null; }
export function integrationHtml(slug: string): string | null { const page = INTEGRATION_PAGES.find((p) => p.slug === slug); return page ? landingPageHtml("integrations", page) : null; }

export function useCasesIndexHtml(): string {
  return layout("VeracityAPI Use Cases for Agents", "Business-function use cases for agents evaluating VeracityAPI.", `<section class="hero"><div class="eyebrow">Agent use cases</div><h1>Business functions agents can protect with content trust scoring.</h1><p class="lead">These pages are written for agents evaluating whether VeracityAPI is worth calling in a workflow. Each use case explains the business value, trigger point, request context, policy mapping, automation recipe, evidence to inspect, KPIs, and caveats.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/openapi.json">OpenAPI</a> <a class="btn" href="/llms.txt">Agent instructions</a></p></section><section class="grid">${USE_CASES.map((u, i) => `<a class="card" href="/use-cases/${u.slug}"><div class="label">${String(i + 1).padStart(2, "0")} · ${esc(u.eyebrow)}</div><h3>${esc(u.title)}</h3><p>${esc(u.summary)}</p></a>`).join("")}</section>`, "/use-cases", "ItemList");
}

export function useCaseHtml(slug: string): string | null {
  const u = USE_CASES.find((item) => item.slug === slug);
  if (!u) return null;
  const modality = u.modality ?? "text";
  const requestBody = modality === "image"
    ? { type: "image", content: u.sampleImageUrl ?? "https://veracityapi.com/demo/influencer-beauty-tonic.jpg", context: u.context, store_content: false }
    : modality === "audio"
      ? { type: "audio", content: "https://veracityapi.com/assets/demo-voice-message.mp3", transcript: "optional caller transcript", context: u.context, store_content: false }
      : { type: "text", content: u.sampleText, context: u.context, store_content: false };
  const requestJson = JSON.stringify(requestBody);
  const requestBlock = `<section class="card"><h3>Request template</h3><p>The exact payload shape this use case sends. The sample below uses representative content for this workflow; substitute your own.</p><pre>curl ${API_BASE_URL}/v1/analyze \\
  -H "Authorization: Bearer $VERACITY_API_KEY" \\
  -H "Content-Type: application/json" \\
  -d '${esc(requestJson)}'</pre></section>`;
  const inputLabel = modality === "image" ? "What image URL to submit" : modality === "audio" ? "What audio URL to submit" : "What text to submit";
  const costNotes = modality === "image"
    ? "Image analysis is a flat $0.02 per image. The endpoint accepts HTTPS image URLs, stores no image bytes, and logs only a URL hash plus hostname. Current v0.1 latency is vision-model-bound, so preflight balance and retry carefully."
    : modality === "audio"
      ? "Audio workflow triage is a flat $0.01 per request. Submit an HTTPS audio URL under the size cap plus optional caller transcript; VeracityAPI returns a Gemini-generated transcript; VeracityAPI stores no audio bytes, base64, or full URL."
      : "Analyze only is $0.005 per 1,000 characters; Analyze + revise with auto_revise=true is $0.010 per 1,000 characters. Both round up to the nearest 1,000 characters. Short captions/emails usually cost $0.005; longer pages or chapters scale linearly by length. Current v0.1 latency is LLM-bound, so batch/concurrent orchestration is recommended for high-volume pipelines.";
  const checklist = modality === "image"
    ? ["Does this workflow have a costly failure mode from manipulated or synthetic-looking visuals?", "Can the agent store evidence categories without storing raw image bytes or full URLs?", "Should this workflow fail open, fail closed, or queue human review if image scoring is unavailable?", "Which field drives policy: recommended_action, risk_level, content_trust_score, or synthetic_image_risk?", "What local provenance check should complement the API score?"]
    : modality === "audio"
      ? ["Is the page clearly marked as beta workflow triage, not forensic proof?", "What consent, retention, and privacy rules govern the audio clips?", "What independent verification is required before consequential decisions?", "How will the agent behave if audio scoring is unavailable or inconclusive?", "Which reviewer outcome should be captured for future calibration?"]
      : ["Does this workflow have a costly failure mode from generic or weak-provenance text?", "Can the agent map evidence spans back to editable source locations?", "Should this workflow fail open, fail closed, or queue human review if VeracityAPI is unavailable?", "Which field drives policy: recommended_action, risk_level, content_trust_score, specificity_risk, or provenance_weakness?", "What local rule should complement the API score?"];
  const policyCode = `if (result.recommended_action === "allow") continueWorkflow();\nif (result.recommended_action === "revise") rewriteWith(result.evidence, result.recommended_fixes);\nif (result.recommended_action === "human_review") queueForHumanReview(result);\nif (result.recommended_action === "reject") discardOrRebuild();`;
  const currentIndex = USE_CASES.findIndex((item) => item.slug === u.slug);
  const siblingLinks = [USE_CASES[(currentIndex + USE_CASES.length - 1) % USE_CASES.length], USE_CASES[(currentIndex + 1) % USE_CASES.length]].map((item) => ({ href: `/use-cases/${item.slug}`, label: item.title, note: item.summary }));
  const related = relatedLinksCard("Related use-case cluster", [
    { href: "/use-cases", label: "All use cases", note: "Browse the full workflow library." },
    ...modalityLinks(u.modality),
    ...siblingLinks,
    { href: "/docs", label: "Implementation docs", note: "Wire this workflow into the API contract." },
  ], "Move from this specific workflow into the nearest modality, sibling jobs, and implementation docs.");
  const whatWeveSeenBlock = u.whatWeveSeen
    ? `<section class="card practitioner-note"><div class="label">What we've seen in practice</div><p>${esc(u.whatWeveSeen)}</p><p class="byline"><em>— Bernard Huang, founder. <a href="/about">About</a></em></p></section>`
    : "";
  const domainNuanceBlock = u.domainNuance
    ? `<section class="card"><h3>${esc(u.domainNuance.title)}</h3><p>${esc(u.domainNuance.body)}</p></section>`
    : "";
  const realExampleBlock = u.realExample
    ? `<section class="card"><h3>A concrete example</h3><p><strong>Setup:</strong> ${esc(u.realExample.setup)}</p><p><strong>Result:</strong> ${esc(u.realExample.result)}</p></section>`
    : "";
  return layout(`${u.title} | VeracityAPI use case`, u.summary, `<section class="hero"><div class="eyebrow">${esc(u.eyebrow)}</div><h1>${esc(u.title)}</h1><p class="lead">${esc(u.summary)}</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/use-cases">All use cases</a> <a class="btn" href="/docs">Docs</a></p></section>
${whatWeveSeenBlock}
<section class="grid"><div class="card"><h3>Business value</h3>${list(u.businessValue)}</div><div class="card"><h3>Agent job to be done</h3><p>${esc(u.agentJob)}</p><p><span class="pill">format: ${esc(u.context.format)}</span><span class="pill">intended_use: ${esc(u.context.intended_use)}</span><span class="pill">domain: ${esc(u.context.domain)}</span></p></div></section>
${domainNuanceBlock}
<section class="grid"><div class="card"><h3>When to call VeracityAPI</h3><p>${esc(u.trigger)}</p><h3>${inputLabel}</h3><p>${esc(u.input)}</p></div><div class="card"><h3>Decision policy</h3>${list(u.policy)}</div></section>
${requestBlock}
<section class="grid"><div class="card"><h3>Automation recipe</h3>${list(u.automation)}</div><div class="card"><h3>Evidence spans agents should inspect</h3>${list(u.evidence)}</div></section>
${realExampleBlock}
<section class="grid"><div class="card"><h3>Policy pseudocode</h3><pre>${policyCode}</pre></div><div class="card"><h3>KPIs to track</h3>${list(u.kpis)}</div></section>
<section class="grid"><div class="card"><h3>What can go wrong</h3>${list(u.caveats)}</div><div class="card"><h3>Cost and latency notes</h3><p>${costNotes}</p></div></section>
<section class="card"><h3>Agent evaluation checklist</h3><ul>${checklist.map((item) => `<li>${esc(item)}</li>`).join("")}</ul></section>${related}`, `/use-cases/${u.slug}`, "TechArticle");
}

export function docsHtml(): string { return layout("VeracityAPI Docs", "API docs for VeracityAPI content trust scoring.", `<section class="docsShell"><aside class="docsSide"><div class="label">Docs</div><a href="#quickstart">Quickstart</a><a href="#response-schema">Response schema</a><a href="#errors">Errors</a><a href="#policy">Action policy</a><a href="#signals">Signal definitions</a><a href="#routing">Routing</a><a href="#sdks">SDKs</a><a href="#media">Media</a><a href="#privacy">Privacy</a></aside><article class="docsMain"><section class="hero" id="quickstart"><div class="eyebrow">Developer docs</div><h1>Quickstart — 5 minutes to your first analyzed result</h1><p class="lead">Call VeracityAPI before an agent publishes, cites, trains on, or moderates text, image, audio, or private-beta video. Results include evidence, limitations, and a workflow-ready <code>recommended_action</code>.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/docs/errors">Error handling</a> <a class="btn" href="/methodology">Trust model</a> <a class="btn" href="/openapi.json">OpenAPI JSON</a></p><div class="docSearch"><input id="docSearch" placeholder="Search docs: response schema, errors, auto_revise, slop_risk…" aria-label="Search docs"/><span id="docSearchCount">Search this page</span></div></section>
<section class="grid" id="endpoints"><div class="card"><div class="label">Step 1</div><h2>Create a key</h2><p>Sign in at <a href="/account">/account</a>, copy an API key, and set it as <code>VERACITY_API_KEY</code>. New accounts include starter credit for production-like smoke tests.</p></div><div class="card"><div class="label">Step 2</div><h2>Send one unified request</h2><pre>curl ${API_BASE_URL}/v1/analyze \\
  -H "Authorization: Bearer API_KEY" \\
  -H "Content-Type: application/json" \\
  -d '{"type":"text","content":"Paste article, review, caption, or source text here...","auto_revise":true,"context":{"format":"article","intended_use":"publish"},"store_content":false}'</pre><p>Use the same endpoint for <code>type:"text"</code>, <code>type:"image"</code>, and <code>type:"audio"</code>; private-beta video can use <code>type:"video"</code> or the canonical typed <code>POST /v1/analyze-video</code>. Text can set <code>auto_revise:true</code> to receive <code>revised_text</code> when the action is <code>revise</code>.</p></div></section>
<section class="grid"><div class="card"><div class="label">Step 3</div><h2>Route on recommended_action</h2><ul><li><code>allow → publish or proceed</code></li><li><code>revise → fix the flagged signals</code></li><li><code>human_review → route to a human</code></li><li><code>reject → block or discard</code></li></ul><p><code>recommended_action</code> is the primary integration field. Scores explain the route; your workflow should branch on the action.</p></div><div class="card"><div class="label">Step 4</div><h2>Inspect evidence and fixes</h2><p>Evidence spans and <code>recommended_fixes</code> tell a writer, generator, moderator, or source-checking agent what to change next. Keep <code>store_content:false</code> when you do not want raw submitted text retained.</p></div></section>
<section class="card" id="response-schema"><h2>Complete response example</h2><p>This mirrors the public OpenAPI response fields developers should expect from text analysis. Media responses keep the same routing spine and add modality-specific risk fields.</p><pre>{
  "analysis_id": "ana_01HX...",
  "modality": "text",
  "content_trust_score": 0.42,
  "synthetic_risk": 0.61,
  "slop_risk": 0.74,
  "specificity_risk": 0.68,
  "provenance_weakness": 0.55,
  "risk_level": "high",
  "recommended_action": "human_review",
  "primary_reason": "unsupported_generic_claims",
  "confidence": "medium",
  "evidence": [{"type":"generic_phrasing","severity":"high","span":"always stay alert","explanation":"Vague advice without sourceable detail."}],
  "recommended_fixes": ["Replace generic warnings with named places, mechanisms, and sourceable evidence."],
  "limitations": ["Workflow signals, not forensic proof."],
  "revised_text": "Only present when auto_revise:true and recommended_action is revise.",
  "billing": {"units_analyzed":1,"bucket":"text_1k_units","price_cents":0.5,"remaining_balance_cents":149.5}
}</pre><table class="table"><tr><th>Field</th><th>Meaning</th></tr><tr><td><code>analysis_id</code></td><td>Stable analysis identifier for logs and support.</td></tr><tr><td><code>modality</code></td><td><code>text</code>, <code>image</code>, <code>audio</code>, or <code>video</code>.</td></tr><tr><td><code>recommended_action</code></td><td>Main workflow route: allow, revise, human_review, or reject.</td></tr><tr><td><code>risk_level</code></td><td>Low, medium, or high summary of the strongest workflow-risk signal.</td></tr><tr><td><code>primary_reason</code></td><td>Single top reason for the route.</td></tr><tr><td><code>confidence</code></td><td>Model confidence in the routing decision.</td></tr><tr><td><code>evidence</code></td><td>Typed spans, cues, or observations behind the decision.</td></tr><tr><td><code>recommended_fixes</code></td><td>Actionable changes for revise/human_review workflows.</td></tr><tr><td><code>limitations</code></td><td>Boundary language, including non-forensic scope.</td></tr><tr><td><code>billing</code></td><td>Units, bucket, price, and remaining balance for authenticated calls.</td></tr></table></section>
<section class="card" id="errors"><h2>Error handling</h2><p>Production integrations should handle validation, credit, rate-limit, and provider failures explicitly. See the full page at <a href="/docs/errors">/docs/errors</a>.</p><table class="table"><tr><th>Status</th><th>Meaning</th><th>Retry?</th></tr><tr><td>400</td><td>validation errors such as missing content, unsupported context, or malformed JSON.</td><td>No; fix request.</td></tr><tr><td>401</td><td>Missing or invalid bearer API key.</td><td>No; refresh key.</td></tr><tr><td>402</td><td>insufficient credits.</td><td>No; add credit or reduce run size.</td></tr><tr><td>413</td><td>content too large.</td><td>No; chunk input.</td></tr><tr><td>415</td><td>unsupported media type.</td><td>No; submit supported HTTPS media.</td></tr><tr><td>429</td><td>rate limited; respect <code>Retry-After</code>.</td><td>Yes, after delay.</td></tr><tr><td>5xx</td><td>transient Worker or provider failure.</td><td>Yes; exponential backoff, max 3 attempts.</td></tr></table></section>
<section class="card" id="policy"><h2>Current thresholds and action policy</h2><p>Text v0.1 uses <code>max(synthetic_risk, slop_risk)</code>: below 0.40 = low, below 0.70 = medium, 0.70+ = high. Audio v0.1 is stricter for pre-publication triage: below 0.30 = low, below 0.55 = medium, 0.55+ = high. Video private beta uses contact-sheet triage: below 0.30 = low, below 0.60 = medium, 0.60+ = high.</p><table class="table"><tr><th>intended_use</th><th>low</th><th>medium</th><th>high</th></tr><tr><td>publish</td><td>allow</td><td>revise</td><td>human_review</td></tr><tr><td>train</td><td>allow</td><td>human_review</td><td>reject</td></tr><tr><td>cite</td><td>allow</td><td>human_review</td><td>reject</td></tr><tr><td>moderate</td><td>allow</td><td>allow</td><td>revise</td></tr><tr><td>other</td><td>allow</td><td>revise</td><td>human_review</td></tr></table></section>
<section class="card" id="signals"><h2>Signal definitions</h2><dl class="definitions"><dt><code>slop_risk</code></dt><dd>Likelihood that text is generic, low-information, padded, or unfit to ship without revision.</dd><dt><code>synthetic_risk</code></dt><dd>Modality-level synthetic-media or AI-texture workflow risk signal; not authorship proof.</dd><dt><code>specificity_risk</code></dt><dd>How much the content lacks concrete names, mechanisms, numbers, examples, or local detail.</dd><dt><code>provenance_weakness</code></dt><dd>Weakness in source context, attribution, corroboration, or traceability.</dd><dt><code>risk_level</code></dt><dd>Low/medium/high rollup used for triage dashboards.</dd><dt><code>confidence</code></dt><dd>How strongly the system trusts the route given input quality and evidence density.</dd><dt><code>primary_reason</code></dt><dd>Top reason to show in a queue or webhook.</dd><dt><code>threshold</code></dt><dd>Your workflow's action cutoff. Tune by intended_use and business risk.</dd><dt><code>intended_use</code></dt><dd>Policy context such as publish, cite, train, moderate, or other.</dd></dl></section>
<section class="grid" id="routing"><div class="card"><h2>Routing snippet</h2><pre>switch (result.recommended_action) {
  case "allow": publish(); break;
  case "revise": rewriteWith(result.evidence, result.recommended_fixes); break;
  case "human_review": queueForReview(result); break;
  case "reject": quarantine(result); break;
}</pre></div><div class="card"><h2>Batch + balance</h2><pre>POST ${API_BASE_URL}/v1/analyze-batch
GET ${API_BASE_URL}/v1/balance</pre><p>Batch supports 1-25 text items. Balance returns account credit and recent usage so agents can check spend before large jobs.</p></div></section>
<section class="grid" id="sdks"><div class="card"><h2>TypeScript SDK</h2><pre>npm install @veracityapi/sdk

import { VeracityAPI } from "@veracityapi/sdk";

const client = new VeracityAPI({ apiKey: process.env.VERACITY_API_KEY });
const result = await client.analyzeText({
  type: "text",
  content: draft,
  auto_revise: true,
  context: { format: "article", intended_use: "publish" }
});</pre></div><div class="card"><h2>Python SDK</h2><pre>pip install veracityapi

from veracityapi import VeracityAPI

client = VeracityAPI()
result = client.analyze_text(
    text,
    auto_revise=True,
    context={"format": "article", "intended_use": "publish"},
)</pre></div></section>
<section class="grid" id="media"><div class="card"><h2>Image curl</h2><pre>curl ${API_BASE_URL}/v1/analyze -H "Authorization: Bearer API_KEY" -H "Content-Type: application/json" -d '{"type":"image","content":"https://example.com/image.jpg","context":{"format":"social_post","intended_use":"moderate"},"store_content":false}'</pre></div><div class="card"><h2>Video private beta</h2><pre>curl ${API_BASE_URL}/v1/analyze-video -H "Authorization: Bearer API_KEY" -H "Content-Type: application/json" -d '{"video_url":"https://example.com/clip.mp4","context":{"format":"social_post","intended_use":"moderate"},"store_content":false}'</pre><p>Direct HTTPS videos only, capped at 30 seconds / 25 MB. Returns <code>synthetic_video_risk</code>, <code>visual_synthetic_risk</code>, <code>metadata_risk</code>, evidence, limitations, and <code>billing.bucket=video_v0</code>. Cost: $0.05 per successful call.</p></div><div class="card"><h2>Audio FAQ</h2><p><strong>Can VeracityAPI detect AI-generated audio?</strong> It can flag synthetic-speech and deepfake voice cues as workflow-risk signals. It is not speaker identity verification or forensic evidence.</p></div></section>
<section class="card" id="privacy"><h2>Privacy defaults</h2><p>Media endpoints store no raw image/audio/video bytes, base64 payloads, contact sheets, frames, or full URLs. Text defaults to <code>store_content=false</code>. See <a href="/privacy">Privacy</a>, <a href="/security">Security</a>, and <a href="/subprocessors">Subprocessors</a>.</p></section></article><aside class="docsToc"><div class="label">On this page</div><a href="#quickstart">Quickstart</a><a href="#response-schema">Response schema</a><a href="/docs/errors">Errors</a><a href="#policy">Policy</a><a href="#signals">Signals</a><a href="#routing">Routing</a><a href="#sdks">SDKs</a><a href="#media">Media</a><a href="#privacy">Privacy</a></aside></section><script>const q=document.getElementById('docSearch'),count=document.getElementById('docSearchCount');if(q){q.oninput=()=>{const term=q.value.toLowerCase();let hits=0;document.querySelectorAll('.docsMain .card,.docsMain .grid').forEach(el=>{const ok=!term||el.textContent.toLowerCase().includes(term);el.style.display=ok?'':'none';if(ok&&term)hits++});count.textContent=term?hits+' matching sections':'Search this page'}}document.querySelectorAll('.copyCode').forEach(b=>b.onclick=async()=>{await navigator.clipboard.writeText(document.getElementById(b.dataset.copyTarget).innerText);b.textContent='Copied';setTimeout(()=>b.textContent='Copy',1200)});</script>`, "/docs", "TechArticle"); }


export function docsErrorsHtml(): string { return layout("VeracityAPI Error Handling", "Error codes, retry policy, rate limits, and timeout guidance for VeracityAPI integrations.", `<section class="hero"><div class="eyebrow">Docs · errors</div><h1>Error handling for production integrations.</h1><p class="lead">Handle authentication, validation, credits, rate limits, and provider failures explicitly. Retry transient failures with exponential backoff; do not retry malformed requests.</p><p><a class="btn primary" href="/docs">Back to docs</a> <a class="btn" href="/account">Get API key</a></p></section><section class="card"><h2>Status codes</h2><table class="table"><tr><th>Status</th><th>Cause</th><th>Client behavior</th></tr><tr><td><code>400</code></td><td>validation errors: malformed JSON, missing content, unsupported context, or invalid URL.</td><td>Fix payload; do not retry unchanged.</td></tr><tr><td><code>401</code></td><td>invalid or missing API key.</td><td>Prompt for a fresh key; do not retry blindly.</td></tr><tr><td><code>402</code></td><td>insufficient credits.</td><td>Show balance/top-up flow or reduce the run.</td></tr><tr><td><code>413</code></td><td>content too large.</td><td>Chunk text or shrink media before retrying.</td></tr><tr><td><code>415</code></td><td>unsupported media type.</td><td>Submit supported HTTPS image/audio/video input.</td></tr><tr><td><code>429</code></td><td>rate limited.</td><td>Respect <code>Retry-After</code>; create a free API key if the public demo limit is reached.</td></tr><tr><td><code>5xx</code></td><td>transient Worker, provider, network, or model failure.</td><td>Retry with exponential backoff, max 3 attempts.</td></tr></table></section><section class="grid"><div class="card"><h2>Timeout guidance</h2><ul><li>Text: use a 30s client timeout.</li><li>Image/audio: use a 60s client timeout.</li><li>Video private beta: use a 45s client timeout; inputs are capped at 30s/25MB and may return <code>503 video_unavailable</code> for extractor/model outages.</li><li>For batches, keep each item within documented caps and treat partial failures as retryable per item.</li></ul></div><div class="card"><h2>Retry policy</h2><p>Use exponential backoff with jitter: 1s, 2s, 4s; max 3 attempts. Do not retry <code>400</code>, <code>401</code>, <code>402</code>, <code>413</code>, or <code>415</code> without changing the request or account state.</p><p>Billing guarantee: if analysis fails before returning a recommendation, it is not charged.</p></div></section><section class="card"><h2>Example 429 body</h2><pre>{"error":"rate_limited","message":"Public demo limit reached. Create a free API key to keep testing with your own content."}</pre></section>`, "/docs/errors", "TechArticle"); }

export function whatWeDetectHtml(): string { return layout("What VeracityAPI Detects", "Concrete examples of VeracityAPI workflow-risk signals across text, image, audio, and video.", `<section class="hero"><div class="eyebrow">What we detect</div><h1>Concrete workflow-risk signals before content ships.</h1><p class="lead">VeracityAPI does not claim forensic proof. It catches AI slop, weak provenance, unsupported claims, and synthetic-media cues that should change how an agent routes content.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/docs">Read docs</a> <a class="btn" href="/#demo">Try live demo</a></p></section><section class="grid"><div class="card"><h2>What we catch</h2><ul><li>Generic AI phrasing patterns.</li><li>Unsupported factual claims.</li><li>Weak provenance / source ambiguity.</li><li>Synthetic-image cues.</li><li>Synthetic-audio cues.</li><li>Low-information filler content.</li></ul></div><div class="card"><h2>What we do not catch</h2><ul><li>Whether a specific person wrote it.</li><li>Whether a claim is objectively true.</li><li>Copyright / IP infringement.</li><li>Hate speech / harassment.</li><li>PII detection.</li><li>Speaker identity proof.</li><li>Courtroom/academic/legal evidence.</li></ul></div></section><section class="grid"><div class="card"><div class="label">Text</div><h2>Generic, low-information phrasing</h2><p><strong>Before:</strong> “In today's fast-paced digital landscape...”</p><p><code>recommended_action=revise</code> · <code>primary_reason=generic_phrasing</code></p><p><strong>Fix:</strong> replace with specific customer, problem, mechanism, and evidence.</p></div><div class="card"><div class="label">Text</div><h2>Unsupported claims presented as fact</h2><p><strong>Before:</strong> “Studies show 87% of users prefer...”</p><p><code>recommended_action=human_review</code> · <code>primary_reason=unsupported_claim</code></p><p><strong>Fix:</strong> cite a source, lower certainty, or remove the claim.</p></div><div class="card"><div class="label">Source risk</div><h2>Weak provenance / source risk</h2><p><strong>Before:</strong> scraped or unattributed source snippet with no corroboration.</p><p><code>recommended_action=human_review</code> · <code>primary_reason=weak_provenance</code></p><p><strong>Fix:</strong> require corroboration before publishing, citing, or training.</p></div><div class="card"><div class="label">Image</div><h2>Synthetic image cues</h2><p>Flags visible artifacts, inconsistent lighting, distorted text/logos, and suspicious provenance context as synthetic media risk.</p><p><code>recommended_action=human_review</code></p><p><strong>Fix:</strong> request original source, metadata, or manual visual review.</p></div><div class="card"><div class="label">Audio</div><h2>Synthetic audio cues</h2><p>Flags synthetic-speech cues, suspicious transcript/prosody, and low-provenance voice notes for review.</p><p><code>recommended_action=human_review</code></p><p><strong>Fix:</strong> verify source, consent, and publication context before use.</p></div></section><section class="card"><h2>Use it like a linter for LLM pipelines</h2><p>Text results prioritize <code>slop_risk</code>, <code>specificity_risk</code>, and <code>provenance_weakness</code>. Image and audio results use AI forgery / synthetic media language instead of calling media “slop.” Every result should drive an action: allow, revise, human_review, or reject.</p></section>`, "/what-we-detect", "TechArticle"); }

export function methodologyHtml(): string { return layout("VeracityAPI Methodology & Trust Model", "The epistemology: what VeracityAPI claims to measure, what it explicitly doesn't, and the trust contract behind every response.", `<section class="hero"><div class="eyebrow">Methodology · what we claim</div><h1>The epistemology, not the implementation.</h1><p class="lead">This page covers what VeracityAPI claims to measure, what it explicitly doesn't, and the trust contract behind every response. For the technical pipeline (model, temperature, thresholds, scoring code), see <a href="/how-it-works">/how-it-works</a>.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/how-it-works">Technical pipeline</a> <a class="btn" href="/evals">Evals</a></p></section>
<section class="card practitioner-note"><div class="label">Why this page exists separately from /how-it-works</div><p>Most AI-detection products blur these together: 'here's what we do' and 'here's how we do it' end up in one document. I split them deliberately. /methodology answers 'what can I trust this for?' — which is the question that should be settled before integration. /how-it-works answers 'what's running under the hood?' — which is the question that matters during integration. Different audiences, different cadences of change.</p><p class="byline"><em>— Bernard Huang, founder. <a href="/about">About</a></em></p></section>
<section class="grid"><div class="card"><h2>What we measure</h2><ul><li><strong>Specificity gaps and generic slop risk</strong> — does the text describe a category or name actual things?</li><li><strong>Provenance weakness</strong> — claims without sources, attributions without traceability, evidence without a chain.</li><li><strong>Visible synthetic-image cues</strong> — for uploaded/public image URLs at v0.1 visual-rubric resolution.</li><li><strong>Synthetic-audio cues and workflow risk</strong> — for short HTTPS audio URLs, with Gemini-generated transcript returned alongside.</li><li><strong>Routing fit</strong> — the deterministic output that says what your workflow should do next: allow, revise, human_review, or reject.</li></ul></div><div class="card"><h2>What we do not claim</h2><ul><li><strong>No proof of human vs AI authorship.</strong> The result is workflow risk, not provenance.</li><li><strong>No legal, academic, employment, identity, or forensic determination.</strong> The response is not court-ready evidence.</li><li><strong>No speaker identity verification or voice-clone proof.</strong> Audio scoring is workflow signal, not identity.</li><li><strong>No guarantee of truth, safety, or legality.</strong> Specific text can still be wrong; generic text can still be true.</li><li><strong>No plagiarism source-matching.</strong> A different category of product solves that problem.</li></ul></div></section>
<section class="card"><h2>The trust contract: what every response actually contains</h2><p>Every /v1/analyze response combines model-observed evidence with deterministic post-processing. Agents should branch on <code>recommended_action</code>, store evidence and limitations alongside the routing decision, and escalate high-stakes uncertainty to humans rather than tightening thresholds.</p><table class="table"><tr><th>Signal</th><th>Purpose</th><th>Safe use</th><th>Unsafe use</th></tr><tr><td><code>content_trust_score</code></td><td>0–1 confidence that content is usable for the workflow.</td><td>Rank queues; monitor quality trends over time.</td><td>Don't use as a threshold; the calibration may shift across versions.</td></tr><tr><td><code>risk_level</code></td><td>Normalized low/medium/high rollup.</td><td>Set default routing thresholds in your local policy.</td><td>Don't treat 'high' as evidence of malfeasance.</td></tr><tr><td><code>recommended_action</code></td><td>Deterministic routing label.</td><td>Branch your code on this field; it's the stable contract.</td><td>Don't show as a probability to a human user — it isn't one.</td></tr><tr><td><code>evidence</code></td><td>Typed spans/cues explaining the route.</td><td>Use as a rewrite prompt; show to a human reviewer.</td><td>Don't treat as exhaustive — evidence is what the model surfaced, not everything it found.</td></tr><tr><td><code>limitations</code></td><td>Boundary language for your UI.</td><td>Display alongside the result so users understand scope.</td><td>Don't hide; the limitations are part of the trust contract.</td></tr></table></section>
<section class="grid"><div class="card"><h2>Privacy posture</h2><p>Default text requests don't retain raw content — <code>store_content</code> defaults to false. Image and audio analysis stores no raw media bytes, no base64 payloads, no full media URLs. Operational logs keep request ID, hashed inputs, hostname, latency, model version — the metadata needed for support and debugging without retaining what you submitted.</p><p>For details on subprocessors and data flow: see <a href="/privacy">Privacy</a>, <a href="/security">Security</a>, and <a href="/subprocessors">Subprocessors</a>.</p></div><div class="card"><h2>Evaluation posture</h2><p>Published evals report routing-action agreement, not authorship detection accuracy. The 2026 benchmark program will publish binary-flagging F1 alongside routing-action F1 once vendor terms, corpus licensing, and frozen artifacts are complete. 'Where Veracity loses' will appear on the page regardless of headline favorability.</p><p>Current published numbers: 0.871 macro F1 on a 500-item seed corpus, 88.0% routing accuracy. See <a href="/evals">evals</a> for per-action precision/recall and reproducible artifacts.</p></div></section>
<section class="card"><h2>Recommended escalation policy by intended_use</h2><p>The policy module isn't a recommendation — it's the deterministic logic the API applies after scoring. When you set <code>intended_use</code> in the request context, the routing thresholds shift accordingly.</p><table class="table"><tr><th>intended_use</th><th>low risk</th><th>medium risk</th><th>high risk</th></tr><tr><td><code>publish</code></td><td>allow</td><td>revise</td><td>human_review</td></tr><tr><td><code>train</code></td><td>allow</td><td>human_review</td><td>reject</td></tr><tr><td><code>cite</code></td><td>allow</td><td>human_review</td><td>reject</td></tr><tr><td><code>moderate</code></td><td>allow</td><td>allow</td><td>revise</td></tr><tr><td><code>other</code></td><td>allow</td><td>revise</td><td>human_review</td></tr></table><p>The asymmetry reflects the cost of getting it wrong. Publishing a marginal page is recoverable; training on it amortizes over millions of inference calls. The intended_use field exists precisely so the policy doesn't have to be uniform across use cases.</p></section>
<section class="card"><h2>When the right answer is 'don't use VeracityAPI'</h2><p>I think every methodology page should include a 'don't use this product if...' section. Here's mine:</p><ul><li><strong>Academic-integrity disciplinary processes.</strong> The score is not authorship proof. If a student's grade or graduation depends on the outcome, this is the wrong tool.</li><li><strong>Employment, hiring, or performance decisions.</strong> Same reason.</li><li><strong>Court-ready synthetic-media forensics.</strong> Forensic vendors (Reality Defender, DeepMedia, others) are built for that and provide the chain-of-custody artifacts courts require.</li><li><strong>Real-time call-center voice-fraud prevention.</strong> Audio scoring is async-triage shaped; for inline call-flow decisions, use a specialized voice-fraud platform.</li><li><strong>Plagiarism source-matching.</strong> Use a plagiarism-specialized tool (Copyleaks, Turnitin, Originality.ai's plagiarism module).</li></ul></section>`, "/methodology", "TechArticle"); }
export const trustModelHtml = methodologyHtml;

export function howItWorksHtml(): string { return layout("How VeracityAPI Works — the technical pipeline", "The implementation: model, temperature, schema, scoring pipeline, threshold logic, and changelog. For what we claim and don't claim, see /methodology.", `<section class="hero"><div class="eyebrow">Technical pipeline · how the scoring runs</div><h1>The implementation, step by step.</h1><p class="lead">This page covers what's running inside the API call: which model, which prompt structure, which post-processing, which thresholds, and what changed in each version. For the epistemology — what VeracityAPI claims to measure and what it doesn't — see <a href="/methodology">/methodology</a>.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/methodology">What we claim</a> <a class="btn" href="/evals">Evals</a></p></section>
<section class="card"><h2>The scoring pipeline, end to end</h2><p>One <code>POST /v1/analyze</code> call goes through the following pipeline. Each step is deterministic given the previous step's output, except for the model call (step 3) which has temperature=0 but is still a model — empirically very stable across reruns, but not bit-identical.</p><ol><li><strong>Validation</strong> — request schema checked via zod; rejects malformed inputs at the worker boundary with a 400 + structured error.</li><li><strong>Pre-processing</strong> — content normalized; for image/audio, the URL is fetched in a sandboxed worker context with strict size and timeout limits.</li><li><strong>Model call</strong> — text uses Anthropic Haiku with temperature=0 and schema-constrained tool output. Image uses a vision LLM with a visible-artifact rubric. Audio uses Gemini for transcript generation and synthetic-speech triage. Video (private beta) uses Claude Haiku vision on a contact-sheet extracted by ffmpeg.</li><li><strong>Post-processing</strong> — model outputs run through deterministic rules: risk levels mapped from raw scores via fixed thresholds, recommended_action derived from risk_level + intended_use via the policy table, evidence categories normalized.</li><li><strong>Response shaping</strong> — the final JSON is assembled with stable field names. Billing metadata is computed and the analysis_id minted (ULID format).</li><li><strong>Persistence</strong> — analysis_id, timestamps, billing, and routing decision logged to D1; raw submitted content is NOT stored unless <code>store_content:true</code> was explicitly set.</li></ol></section>
<section class="grid"><div class="card"><h2>Text scoring (v0.1)</h2><p><strong>Model:</strong> Anthropic Haiku, temperature=0, schema-constrained tool output.</p><p><strong>Prompt structure:</strong> The model receives the content plus context (format, intended_use, domain) and is asked to return a structured tool call with the evidence array, primary_reason, and individual risk scores. No free-form output.</p><p><strong>Signals scored:</strong> specificity_risk, provenance_weakness, slop_risk, synthetic_texture_risk. The rollup is <code>risk_level = bucket(max(synthetic_risk, slop_risk))</code>.</p><p><strong>Calibration:</strong> 0.871 macro F1 on the 500-item seed corpus across human firsthand, dry factual, generic slop, polished AI-with-specifics, and adversarial samples.</p></div><div class="card"><h2>Image scoring (v0.1)</h2><p><strong>Model:</strong> A vision LLM with a structured visible-artifact rubric.</p><p><strong>Input:</strong> Public HTTPS image URL. The image is fetched in a sandboxed context, scored, and discarded — no bytes stored.</p><p><strong>Signals scored:</strong> synthetic_image_risk (alias: synthetic_risk), plus typed evidence categories (synthetic_texture, geometry_inconsistency, text_artifact, lighting_mismatch).</p><p><strong>Known limit:</strong> v0.1 does NOT inspect EXIF or C2PA metadata. The signal is visual-only. Provenance verification is on the v0.2 roadmap.</p></div><div class="card"><h2>Audio scoring (v0.1)</h2><p><strong>Model:</strong> Gemini for transcript generation and strict synthetic-speech workflow triage.</p><p><strong>Input:</strong> HTTPS audio URL (capped at the size limit) plus optional caller-supplied transcript. VeracityAPI generates a fresh transcript regardless.</p><p><strong>Signals scored:</strong> synthetic_audio_risk, workflow_risk, evidence categories (synthetic_prosody, pause_artifact, background_inconsistency, transcript_urgency).</p><p><strong>Returns:</strong> the Gemini-generated transcript alongside the score — often the more immediately actionable artifact than the risk number, especially on compressed phone clips.</p></div><div class="card"><h2>Video scoring (v0.1 private beta)</h2><p><strong>Model:</strong> Claude Haiku vision on a contact-sheet input.</p><p><strong>Pipeline:</strong> A zero-idle ffmpeg extractor samples six representative frames into a 3x2 contact sheet and returns safe metadata (duration, resolution, codec). Claude Haiku scores visual synthetic-video cues and metadata risk in one structured call.</p><p><strong>Privacy:</strong> No raw video, no extracted frames, no contact sheet, no full URL stored. Only URL hash, hostname, safe metadata, and the action/risk result persist.</p></div></section>
<section class="card"><h2>Threshold table (the actual numbers)</h2><p>This is the deterministic mapping from raw scores to <code>risk_level</code> bands. Different modalities have different bands because the score distributions differ. These thresholds may shift across version bumps; if your code is depending on the underlying score thresholds, branch on <code>recommended_action</code> instead.</p><table class="table"><tr><th>Modality</th><th>low</th><th>medium</th><th>high</th><th>Notes</th></tr><tr><td><strong>Text</strong></td><td>max(synthetic_risk, slop_risk) &lt; 0.40</td><td>&lt; 0.70</td><td>≥ 0.70</td><td>The 'slop or synthetic, whichever is worse' rule.</td></tr><tr><td><strong>Audio</strong></td><td>&lt; 0.30</td><td>&lt; 0.55</td><td>≥ 0.55</td><td>Stricter than text because audio scoring uncertainty cuts more downstream.</td></tr><tr><td><strong>Video (beta)</strong></td><td>&lt; 0.30</td><td>&lt; 0.60</td><td>≥ 0.60</td><td>Contact-sheet sampling means the threshold reflects per-clip uncertainty.</td></tr></table><pre>risk_level = bucket(max(synthetic_risk, slop_risk))
recommended_action = policy(risk_level, intended_use)</pre><p>The <code>policy</code> function is the table on <a href="/methodology#recommended-escalation-policy">/methodology</a> — different intended_use values shift the action up or down a band.</p></section>
<section class="card"><h2>Version changelog</h2><p>Major version bumps are documented here; minor calibration changes appear in <a href="/changelog">/changelog</a>.</p><table class="table"><tr><th>Version</th><th>Date</th><th>What changed</th></tr><tr><td><strong>v0.1</strong></td><td>2026-Q1</td><td>Initial release. Text scoring on Anthropic Haiku with schema-constrained tool output. Image scoring on vision LLM with visual-artifact rubric. Audio scoring on Gemini with transcript return. Video private beta on Claude Haiku contact-sheet pipeline.</td></tr><tr><td><strong>v0.2 (planned)</strong></td><td>2026-H2</td><td>Public-source EXIF/C2PA inspection for image scoring. Multilingual text calibration improvements. Async batch endpoints with webhook delivery. Configurable risk-tolerance modes (lenient/standard/strict).</td></tr></table></section>
<section class="grid"><div class="card"><h2>Known limitations of v0.1</h2><ul><li>Does not prove text was AI-written or human-written. The score is workflow risk, not provenance.</li><li>Good AI-assisted writing with concrete details may pass — and should, because the workflow risk is genuinely low.</li><li>Weak human writing may be flagged. That's also working as intended; the signal is helpfulness, not authorship.</li><li>English-first text calibration. Non-English coverage is weaker until the multilingual eval expansion lands.</li><li>Latency is LLM-bound. Use <code>/v1/analyze-batch</code> (1–25 items) and <code>/v1/balance</code> preflight for high-volume workflows.</li><li>Audio scoring is intentionally strict and can produce false positives on heavily-processed but real recordings (noise suppression, beauty-audio filters, podcast leveling).</li><li>Video private beta is capped at 30 seconds and 25 MB per clip.</li></ul></div><div class="card"><h2>v0.2 roadmap (commitments + maybes)</h2><p><strong>Committed:</strong></p><ul><li>Public-source EXIF and C2PA inspection for image scoring.</li><li>Multilingual text calibration with published per-language coverage tables.</li><li>Async batch endpoints with webhook delivery for jobs &gt;1000 items.</li><li>Configurable risk-tolerance modes (lenient / standard / strict).</li></ul><p><strong>Likely but not committed:</strong></p><ul><li>Fine-tuned classifier replacing the LLM scoring pass for text — pending eval evidence that it improves on the structured-LLM approach.</li><li>Fast heuristic prefilter before the full evidence pass, for cost-sensitive workflows.</li><li>Public-source training-data certification (the dataset behind the multilingual calibration).</li></ul></div></section>
<section class="card"><h3>Image and audio scoring v0.1</h3><p><code>POST /v1/analyze</code> accepts <code>{type:"image",content:"https://..."}</code>, calls a vision LLM with a constrained visible-artifact rubric, and returns <code>synthetic_image_risk</code>, <code>synthetic_risk</code> alias, evidence, fixes, trust score, risk level, and recommended action. VeracityAPI stores no image bytes and logs only a URL hash plus hostname. C2PA/EXIF/provenance verification is roadmap, not claimed in v0.1.</p><p><code>POST /v1/analyze</code> accepts <code>{type:"audio",content:"https://..."}</code> plus optional caller transcript; VeracityAPI returns a Gemini-generated transcript, sends capped audio bytes to Gemini for strict synthetic-audio workflow triage with transcript return, and returns <code>synthetic_audio_risk</code>, <code>workflow_risk</code>, evidence, fixes, trust score, risk level, and recommended action. VeracityAPI stores no audio bytes, base64, or full audio URLs. It is not proof of AI generation, voice cloning, speaker identity, or forensic determination.</p></section>
<section class="grid"><div class="card"><h3>Known limitations</h3><ul><li>Does not prove whether text was written by AI or a human.</li><li>Good AI-assisted writing with concrete details may pass.</li><li>Weak human writing may be flagged — intentionally, if it is generic or unsupported.</li><li>English-calibrated first; non-English scoring is experimental until evals exist.</li><li>Latency is LLM-bound; use /v1/analyze-batch for pipeline batches and /v1/balance for preflight spend checks.</li><li>Audio scoring is intentionally strict for triage and can produce false positives on compressed, edited, or unusually clean human recordings.</li></ul></div><div class="card"><h3>Near-term roadmap</h3><ul><li>Publish a labeled calibration set with false-positive slices.</li><li>Add configurable risk tolerance: lenient, standard, strict.</li><li>Add a fast heuristic prefilter before the full evidence pass.</li><li>Add async batch/webhooks after synchronous batch usage is proven.</li></ul></div></section>`, "/how-it-works", "TechArticle"); }

export function evalsHtml(): string { return layout("VeracityAPI Evals", "Routing-action benchmark evidence, confusion matrix, and known limits for VeracityAPI.", `<section class="hero"><div class="eyebrow">Benchmark proof · v0.1.0</div><h1>We measure routing-action F1, not authorship certainty.</h1><p class="lead">VeracityAPI is judged on whether an agent routes content to the right next action: <code>allow</code>, <code>revise</code>, <code>human_review</code>, or <code>reject</code>. The first published seed benchmark contains 500 labeled text samples across firsthand human writing, dry factual human writing, generic AI slop, polished AI-with-specifics, and edge/adversarial mixed cases.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/for-agents">For agents</a> <a class="btn" href="/docs">Docs</a></p></section>
<section class="grid triple"><div class="card"><div class="label">Seed corpus</div><div class="stat">500</div><p>Balanced five-slice text corpus in <code>data/evals/veracityapi_seed_corpus_500.jsonl</code>.</p></div><div class="card"><div class="label">Routing accuracy</div><div class="stat good">88.0%</div><p>Seed v0.1 action agreement on allow / revise / human_review labels.</p></div><div class="card"><div class="label">Macro F1</div><div class="stat good">0.871</div><p>Macro F1 across supported routing actions; reject has zero support in this seed set.</p></div></section>
<section class="card"><h2>Confusion matrix</h2><table class="table"><tr><th>Expected → Predicted</th><th>allow</th><th>revise</th><th>human_review</th><th>reject</th></tr><tr><td>allow</td><td>190</td><td>10</td><td>0</td><td>0</td></tr><tr><td>revise</td><td>20</td><td>175</td><td>5</td><td>0</td></tr><tr><td>human_review</td><td>0</td><td>25</td><td>75</td><td>0</td></tr><tr><td>reject</td><td>0</td><td>0</td><td>0</td><td>0</td></tr></table><p class="hint">Artifacts: <code>data/evals/veracityapi_seed_results_v0_1.json</code>, <code>data/evals/veracityapi_seed_metrics_v0_1.csv</code>, and <code>scripts/evals-summary.mjs</code>. This is a transparent seed calibration asset, not a forensic benchmark certification.</p></section>
<section class="grid"><div class="card"><h2>Per-action metrics</h2><table class="table"><tr><th>Action</th><th>Precision</th><th>Recall</th><th>F1</th><th>Support</th></tr><tr><td>allow</td><td>0.905</td><td>0.950</td><td>0.927</td><td>200</td></tr><tr><td>revise</td><td>0.833</td><td>0.875</td><td>0.854</td><td>200</td></tr><tr><td>human_review</td><td>0.938</td><td>0.750</td><td>0.833</td><td>100</td></tr></table></div><div class="card"><h2>Dataset slices</h2><ul><li>100 human firsthand samples</li><li>100 dry factual human samples</li><li>100 generic AI slop samples</li><li>100 polished AI-with-specifics samples</li><li>100 edge/mixed/adversarial samples</li></ul></div></section>
<section class="grid"><div class="card"><h2>Comparison scaffold</h2><p><strong>External comparison pending.</strong> Comparator columns are planned for GPTZero, Sapling, and an LLM judge. The metric will be routing-action F1, not detector-score accuracy.</p></div><div class="card"><h2>External comparators</h2><p>GPTZero, Sapling, and GPT-4o judge adapters are documented as planned comparator slots. They were not run in this shipment because no comparator keys were available in the local environment. The public claim remains routing-action F1, not AI-authorship proof; VeracityAPI reports workflow routing quality, not binary authorship evidence.</p></div><div class="card"><h2>What this proves</h2><p>The API contract is optimized for agents: inspect evidence, follow <code>recommended_action</code>, and measure reviewer agreement. The next iteration should replace seed expected labels with blind human labels and add competitor outputs where keys are available.</p></div></section>
<section class="card"><h2>Known limits</h2><ul><li>Seed labels are for workflow routing, not truth or authorship adjudication.</li><li>Reject needs a dedicated abuse/spam corpus before reporting a meaningful reject F1.</li><li>Image and audio need separate labeled corpora before publishing comparable metrics.</li><li>Scores should be paired with local policy and human escalation for high-stakes workflows.</li></ul></section>`, "/evals", "TechArticle"); }

export function forAgentsHtml(): string { return layout("VeracityAPI for Agents", "When agents should call VeracityAPI, how to route recommended_action, pricing, evidence, limitations, and comparisons.", `<section class="hero"><div class="eyebrow">For agents</div><h1>Call VeracityAPI before your workflow trusts content.</h1><p class="lead">Agents should call VeracityAPI at irreversible or high-leverage content checkpoints: before publishing, citing, indexing, training on, moderating, or accepting text, image URLs, audio URLs, and private-beta video URLs from uncertain sources.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/openapi.json">OpenAPI</a> <a class="btn" href="/llms.txt">llms.txt</a></p></section>
<section class="grid"><div class="card"><h2>When to call</h2><ul><li>Before publishing generated drafts, captions, product copy, reviews, or SEO pages.</li><li>Before adding scraped/user-submitted text to RAG, training data, or citation workflows.</li><li>Before accepting uploaded images, voice notes, podcasts, short video clips, or media assets into a public workflow.</li><li>When an agent needs evidence-backed routing instead of a raw detector percentage.</li></ul></div><div class="card"><h2>When not to call</h2><ul><li>Do not use as forensic proof, legal proof, academic misconduct proof, speaker identity verification, or guaranteed truth detection.</li><li>Do not submit secrets, regulated personal data, or private media unless your policy permits it.</li><li>Do not block high-stakes human claims without review; route uncertainty to humans.</li></ul></div></section>
<section class="card"><h2>Agent decision policy templates</h2><div class="grid triple"><div><h3>Policy: pre-publish QA</h3><pre>if (result.recommended_action === "allow") publish();
if (result.recommended_action === "revise") rewriteWith(result.evidence);
if (result.recommended_action === "human_review") queueEditor();
if (result.recommended_action === "reject") blockPublish();</pre></div><div><h3>Policy: RAG/source triage</h3><pre>if (result.recommended_action === "allow") indexSource();
if (result.recommended_action === "human_review") requireCorroboration();
if (result.recommended_action === "reject") quarantineSource();</pre></div><div><h3>Policy: UGC/media moderation</h3><pre>if (["image","audio","video"].includes(result.modality)) attachMediaReview(result);
if (["human_review","reject"].includes(result.recommended_action)) escalate();</pre></div></div></section>
<section class="grid"><div class="card"><h2>Framework recipes</h2><ul><li>TypeScript SDK: <code>npm install @veracityapi/sdk</code> and call <code>new VeracityAPI().analyzeText()</code>.</li><li>Python SDK: <code>pip install veracityapi</code> and call <code>VeracityAPI().analyze_text()</code>.</li><li>OpenAI tool schema: import <code>/openapi.json</code> or define a tool around <code>POST /v1/analyze</code>.</li><li>Vercel AI SDK tool: expose <code>analyzeContent</code> and branch on <code>recommended_action</code>.</li><li>LangGraph conditional edge: route graph edges from <code>allow</code>, <code>revise</code>, <code>human_review</code>, and <code>reject</code>.</li></ul></div><div class="card"><h2>Primary reason enum-like values</h2><p>Use <code>modality</code>, <code>recommended_action</code>, and <code>primary_reason</code> for stable branching. Current enum-like values include <code>unsupported_generic_claims</code>, <code>weak_provenance</code>, <code>synthetic_texture</code>, <code>visible_synthetic_media_cues</code>, <code>synthetic_speech_cues</code>, <code>workflow_context_risk</code>, <code>low_risk_content</code>, and <code>low_risk_media</code>.</p></div></section>
<section class="card"><h2>Endpoint</h2><pre>POST https://api.veracityapi.com/v1/analyze
Authorization: Bearer $VERACITY_API_KEY
Content-Type: application/json

{"type":"text|image|audio|video","content":"...","store_content":false}</pre><p>Legacy typed endpoints remain live, but new agent integrations should prefer the unified endpoint.</p></section>
<section class="grid"><div class="card"><h2>Routing policy</h2><table class="table"><tr><th>recommended_action</th><th>Agent behavior</th></tr><tr><td><code>allow</code></td><td>Continue the workflow.</td></tr><tr><td><code>revise</code></td><td>Use evidence and recommended_fixes to rewrite, replace, or request better provenance.</td></tr><tr><td><code>human_review</code></td><td>Queue with evidence, risk_level, confidence, limitations, and source metadata.</td></tr><tr><td><code>reject</code></td><td>Discard, quarantine, or block according to local policy.</td></tr></table></div><div class="card"><h2>Pricing</h2><ul><li>Text Analyze only: $0.005 / 1k characters.</li><li>Text Analyze + revise: $0.010 / 1k characters with <code>auto_revise:true</code>.</li><li>Image URL analysis: $0.02/image.</li><li>Audio URL analysis: $0.01/request.</li><li>Private-beta video URL analysis: $0.05/successful request (<code>video_v0</code>).</li><li>Use <code>GET /v1/balance</code> before autonomous runs.</li></ul></div></section>
<section class="grid"><div class="card"><h2>Proof</h2><p>Seed benchmark: 500 samples, 88.0% routing-action agreement, macro F1 0.871. See <a href="/evals">/evals</a>. Framing is routing-action quality, not authorship proof.</p></div><div class="card"><h2>Limitations</h2><p>VeracityAPI is a workflow-risk triage API. It does not prove content is AI-generated, true, false, cloned, or legally attributable. Image/audio/video v0.1 do not inspect EXIF/C2PA, speaker identity, or frame-by-frame temporal consistency.</p></div></section>
<section class="card"><h2>How it compares</h2><table class="table"><tr><th>Need</th><th>Use VeracityAPI when...</th><th>Use detector/forensics vendors when...</th></tr><tr><td>Agent routing</td><td>You need allow/revise/human_review/reject plus evidence.</td><td>You only need an authorship probability or investigation workflow.</td></tr><tr><td>Pre-publish QA</td><td>You want generic/slop/provenance checks before publication.</td><td>You need plagiarism databases or institution workflows.</td></tr><tr><td>Synthetic media</td><td>You need async uploaded-media triage with clear limitations.</td><td>You need identity, courtroom evidence, or real-time fraud prevention.</td></tr></table></section>`, "/for-agents", "TechArticle"); }

export function mcpHtml(): string { return layout("VeracityAPI MCP", "MCP tools for calling VeracityAPI from Claude Desktop, Cursor, Claude.ai custom connectors, and compatible agent clients.", `<section class="hero"><div class="eyebrow">MCP distribution</div><h1>Content verification tools for MCP agents.</h1><p class="lead">Install the local MCP wrapper for desktop clients or connect hosted remote MCP at <code>https://api.veracityapi.com/mcp</code> so Claude.ai custom connectors and other MCP clients can call VeracityAPI tools for text, image, audio, private-beta video, batch analysis, and balance preflight.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/integrations/mcp">Integration details</a> <a class="btn" href="https://github.com/psyduckler/veracityapi/tree/main/packages/mcp">Package source</a></p></section>
<section class="card"><h2>Install</h2><pre>{
  "mcpServers": {
    "veracityapi": {
      "command": "npx",
      "args": ["-y", "@veracityapi/mcp"],
      "env": { "VERACITY_API_KEY": "YOUR_API_KEY" }
    }
  }
}</pre><p class="hint">Live on npm: <a href="https://www.npmjs.com/package/@veracityapi/mcp"><code>@veracityapi/mcp@0.1.0</code></a>. Install with <code>npx -y @veracityapi/mcp</code>; keep <code>VERACITY_API_KEY</code> in the MCP server environment.</p></section>
<section class="card"><h2>Remote MCP</h2><pre>{
  "mcpServers": {
    "veracityapi": {
      "url": "https://api.veracityapi.com/mcp",
      "headers": { "Authorization": "Bearer $VERACITY_API_KEY" }
    }
  }
}</pre><p class="hint">Use this hosted endpoint for Claude.ai custom connectors and any MCP client that supports Streamable HTTP JSON-RPC. Prefer Authorization headers when the client supports them. The endpoint exposes <code>initialize</code>, <code>tools/list</code>, and <code>tools/call</code>.</p></section>
<section class="grid"><div class="card"><h2>Tools</h2><ul><li><code>verify_content</code> as the primary smart tool for text, image, audio, URL, and base64 media inputs.</li><li><code>analyze_text</code>, <code>analyze_image</code>, <code>analyze_audio</code>, <code>analyze_video</code>, and <code>analyze_batch</code> remain available for typed compatibility.</li><li><code>check_balance</code> for autonomous preflight spend checks.</li><li><code>get_balance</code> as a compatibility alias for <code>check_balance</code>.</li></ul></div><div class="card"><h2>Distribution status</h2><ul><li>NPM package: <a href="https://www.npmjs.com/package/@veracityapi/mcp"><code>@veracityapi/mcp@0.1.0</code></a>.</li><li>Source package: <code>packages/mcp</code>.</li><li>Build/test/pack and install-smoke verification passed before publish.</li><li>Remote MCP is live at <code>https://api.veracityapi.com/mcp</code> for Claude.ai custom connectors and compatible hosted clients.</li><li>Claude connector instructions: <a href="/integrations/claude"><code>/integrations/claude</code></a>.</li></ul></div></section>
<section class="card"><h2>Safety defaults</h2><p>Never paste API keys into prompts. Keep <code>VERACITY_API_KEY</code> in the MCP server environment. Image, audio, and video MCP calls force <code>store_content:false</code>; raw media bytes, base64, frames/contact sheets, and full media URLs are not stored by default. Video private beta is capped at 30s/25MB and costs $0.05 per successful call.</p></section>`, "/mcp", "TechArticle"); }


export function examplesHtml(): string { return layout("VeracityAPI Examples", "Use cases and integration patterns for VeracityAPI.", `<section class="hero"><div class="eyebrow">Examples</div><h1>Copy-paste VeracityAPI into your agent stack.</h1><p class="lead">Use these wrappers as drop-in gates before agents publish, cite, train on, or moderate content. Each wrapper preserves <code>risk_level</code>, <code>recommended_action</code>, evidence, and limitations.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/use-cases">Open use case library</a> <a class="btn" href="/docs">Docs</a></p></section>
<section class="grid"><div class="card"><h3>LangChain @tool + Python SDK</h3><pre>from langchain_core.tools import tool
from veracityapi import VeracityAPI

client = VeracityAPI()

@tool
def veracity_content_gate(text: str, intended_use: str = "publish") -> dict:
    """Score content trust risk before an agent acts."""
    return client.analyze_text(
        text,
        context={"format": "article", "intended_use": intended_use},
    )</pre></div>
<div class="card"><h3>Vercel AI SDK tool</h3><pre>import { tool } from "ai";
import { z } from "zod";
import { VeracityAPI } from "@veracityapi/sdk";

const veracity = new VeracityAPI({ apiKey: process.env.VERACITY_API_KEY });

export const veracityContentGate = tool({
  description: "Route content by trust risk before publish/cite/train/moderate.",
  parameters: z.object({ text: z.string(), intendedUse: z.string().default("publish") }),
  execute: async ({ text, intendedUse }) => veracity.analyzeText({
    text,
    context: { format: "article", intended_use: intendedUse }
  })
});</pre></div>
<div class="card"><h3>LlamaIndex FunctionTool</h3><pre>from llama_index.core.tools import FunctionTool
from veracityapi import VeracityAPI

client = VeracityAPI()

def veracity_content_gate(text: str, intended_use: str = "publish"):
    return client.analyze_text(text, context={"format": "article", "intended_use": intended_use})

veracity_tool = FunctionTool.from_defaults(fn=veracity_content_gate)</pre></div>
<div class="card"><h3>LangGraph routing node</h3><pre>import { VeracityAPI } from "@veracityapi/sdk";

const veracity = new VeracityAPI({ apiKey: process.env.VERACITY_API_KEY });

async function veracityGate(state) {
  return { ...state, veracity: await veracity.analyzeText({
    text: state.draft,
    auto_revise: true,
    context: { format: "article", intended_use: "publish" }
  }) };
}
function routeByVeracity(state) {
  return state.veracity.recommended_action; // allow | revise | human_review | reject
}</pre></div></section>
<section class="card"><h3>MCP local client config</h3><p>Use this for Claude Desktop, Cursor, and local MCP clients. Hosted remote MCP is live at <code>https://api.veracityapi.com/mcp</code> for compatible custom connectors.</p><pre>{
  "mcpServers": {
    "veracityapi": {
      "command": "npx",
      "args": ["-y", "@veracityapi/mcp"],
      "env": { "VERACITY_API_KEY": "YOUR_API_KEY" }
    }
  }
}</pre></section>
<section class="grid">${USE_CASES.slice(0, 6).map((u) => `<a class="card" href="/use-cases/${u.slug}"><h3>${esc(u.title)}</h3><p>${esc(u.summary)}</p></a>`).join("")}</section>`, "/examples", "TechArticle"); }

export function privacyHtml(): string { return layout("VeracityAPI Privacy", "Privacy, retention, subprocessors, Chrome extension data handling, and API data handling notes for VeracityAPI.", `<section class="hero"><div class="eyebrow">Privacy</div><h1>VeracityAPI runs only when you or your app explicitly submit content.</h1><p class="lead">VeracityAPI is built for content trust workflows where users may submit sensitive drafts, source text, public image URLs, audio URLs, or private-beta video URLs. The default request mode avoids storing raw text; media analysis never stores raw media bytes, base64 payloads, frames/contact sheets, or full media URLs.</p><p class="hint">Last updated: May 17, 2026. Privacy contact: <a href="mailto:hello@veracityapi.com">hello@veracityapi.com</a>. Security disclosures: <a href="mailto:security@veracityapi.com">security@veracityapi.com</a>.</p></section>
<section class="grid"><div class="card"><h2>Chrome extension data</h2><p>The Veracity Chrome extension only checks content when a user explicitly chooses Veracity from the right-click menu. Text checks send selected text, up to 4,000 characters. Image checks send the selected public HTTPS image URL. The extension may include basic page/source domain context when available.</p></div><div class="card"><h2>Extension non-collection</h2><p>The extension does not automatically scan pages, collect browsing history, run content scripts, capture screenshots, upload local image bytes, or bypass private/login-gated images. Private, embedded, <code>blob:</code>, <code>data:</code>, local-file, or non-HTTPS images may fail by design.</p></div></section>
<section class="grid"><div class="card"><h2>Extension storage</h2><p>The extension stores an extension-scoped account API key in Chrome local extension storage. It also stores temporary local job/result metadata so the result popup can display the active check; these local jobs/results are cleaned up after 24 hours.</p></div><div class="card"><h2>API data we process</h2><p>Requests may include text, HTTPS media URLs, optional transcript/context, account email, API-key metadata, billing records, user agent, hashed IP, latency, model version, and response JSON. Do not submit secrets or regulated personal data unless your policy permits it.</p></div></section>
<section class="grid"><div class="card"><h2>Default API retention</h2><p><code>store_content=false</code> is the default. Raw submitted text is stored as null; Veracity logs metadata, hashes, context, response JSON, latency, and model version for debugging, billing, abuse prevention, and product quality. Response JSON can include evidence snippets, recommended fixes, policy matches, and for audio a generated transcript, so do not submit sensitive content unless your policy permits that derived-output retention.</p></div><div class="card"><h2>Media handling</h2><p>Image and audio requests fetch submitted media transiently for model analysis. Video requests use a narrow extractor to transiently download a direct HTTPS video, enforce 30s/25MB caps, create one 3x2 contact sheet plus safe metadata, and discard raw video/frames/contact sheets. Veracity does not persist raw image/audio/video bytes, base64 payloads, frames/contact sheets, or full media URLs. Logs keep a URL hash and hostname so issues can be debugged without storing the full URL.</p></div></section>
<section class="grid"><div class="card"><h2>Subprocessors</h2><p>Current subprocessors include Cloudflare for hosting, D1, Workers, logs, and edge delivery; Anthropic for text scoring/revision and video contact-sheet vision scoring; Google Gemini for audio and selected media analysis; Modal for zero-idle video contact-sheet extraction; Stripe for billing; Resend for login email; GitHub/npm/PyPI for source and package distribution; and Google Analytics for website analytics where enabled.</p></div><div class="card"><h2>Your controls</h2><p>You can revoke API keys, delete your account, request deletion/export, and ask privacy questions by emailing <a href="mailto:hello@veracityapi.com">hello@veracityapi.com</a>. Public demos force privacy-safe defaults and rate limits.</p></div></section>
<section class="card"><h2>Limitations</h2><p>Veracity is a focused v0.1 service, not a regulated-data platform, DPA-backed enterprise contract, forensic lab, or legal/compliance decision system. Scores are probabilistic workflow-risk signals and should be paired with local policy and human escalation for high-stakes uses.</p><p><a class="btn primary" href="/terms">Terms</a> <a class="btn" href="/subprocessors">Subprocessors</a> <a class="btn" href="/security">Security</a></p></section>`, "/privacy", "PrivacyPolicy"); }

export function subprocessorsHtml(): string { return layout("VeracityAPI Subprocessors", "Current subprocessors used to operate VeracityAPI.", `<section class="hero"><div class="eyebrow">Subprocessors</div><h1>Current providers used to operate VeracityAPI.</h1><p class="lead">This page is a public vendor-trust surface for evaluators. It is informational, not a signed DPA or procurement packet. Last updated: 2026-05-17.</p></section><section class="card"><table class="table"><tr><th>Provider</th><th>Purpose</th><th>Data categories</th><th>Region</th></tr><tr><td>Cloudflare</td><td>Workers hosting, D1 database, edge delivery, logs</td><td>Requests, metadata, account and usage records</td><td>Global edge / US data residency</td></tr><tr><td>Anthropic</td><td>Text scoring, optional revision, and image/video vision scoring (Claude Haiku)</td><td>Submitted text/context for text analysis; transient image bytes or video contact-sheet frames for vision scoring; not stored after the call</td><td>US</td></tr><tr><td>Google Gemini</td><td>Audio analysis and transcript generation</td><td>Transient audio bytes or media-derived context sent for analysis; not stored after the call</td><td>US</td></tr><tr><td>Modal</td><td>Zero-idle video contact-sheet extraction for the private-beta video endpoint</td><td>Transient video bytes during extraction; frames passed to vision model; not stored after the call</td><td>US</td></tr><tr><td>Stripe</td><td>Checkout and billing</td><td>Billing identifiers and payment metadata</td><td>US</td></tr><tr><td>Resend</td><td>Magic-link email delivery</td><td>Email address and login-link email content</td><td>US/EU</td></tr><tr><td>GitHub / npm / PyPI</td><td>Source and SDK/MCP package distribution</td><td>Public source code, published package binaries; no customer content</td><td>US</td></tr><tr><td>Google Analytics</td><td>Website analytics where enabled (opt-in via cookie banner)</td><td>Page and browser analytics metadata</td><td>US/global</td></tr></table></section><section class="card"><p>Privacy and deletion/export requests: <a href="mailto:hello@veracityapi.com">hello@veracityapi.com</a>. Security disclosures: <a href="mailto:security@veracityapi.com">security@veracityapi.com</a>.</p></section>`, "/subprocessors", "WebPage"); }

export function securityHtml(): string { return layout("VeracityAPI Security", "Security posture and responsible disclosure for VeracityAPI.", `<section class="hero"><div class="eyebrow">Security</div><h1>Security posture for a focused v0.1 API.</h1><p class="lead">VeracityAPI keeps the security surface deliberately small: Cloudflare Worker, D1, bearer API keys, privacy-safe media logging, request IDs, and explicit non-forensic limitations.</p></section><section class="grid"><div class="card"><h2>Controls in place</h2><ul><li>Bearer API keys; keep them server-side.</li><li>Default no raw text retention via <code>store_content=false</code>.</li><li>No persisted raw media bytes/base64/full media URLs.</li><li>Security headers and restricted browser CORS.</li><li>Public <code>/.well-known/security.txt</code> for disclosure contact.</li></ul></div><div class="card"><h2>Responsible disclosure</h2><p>Email security reports to <a href="mailto:security@veracityapi.com">security@veracityapi.com</a>. Include reproduction steps, affected endpoint, impact, and whether any data was accessed. Do not attack customer data or disrupt service.</p></div></section><section class="card"><h2>Not yet claimed</h2><p>No SOC 2, formal bug bounty, external pentest, enterprise SLA, or DPA is claimed for v0.1 unless separately agreed in writing.</p></section>`, "/security", "WebPage"); }


export function termsHtml(): string { return layout("VeracityAPI Terms of Service", "Terms of Service for VeracityAPI accounts, APIs, demos, MCP tools, and integrations.", `<section class="hero"><div class="eyebrow">Terms of Service</div><h1>Terms for using VeracityAPI.</h1><p class="lead">These terms govern access to VeracityAPI websites, demos, APIs, SDKs, MCP tools, and related integrations. By using VeracityAPI, you agree to use it as a workflow-risk and content-trust tool, not as forensic proof of authorship, identity, truth, or legality.</p><p class="hint">Last updated: May 11, 2026. Contact: <a href="mailto:hello@veracityapi.com">hello@veracityapi.com</a>. Informational terms; not legal advice.</p></section>
<section class="grid"><div class="card"><h2>1. Service purpose</h2><p>VeracityAPI provides probabilistic content-trust, specificity, provenance, synthetic-media workflow-risk, and recommended-action signals for text, image URLs, audio URLs, and private-beta video URLs. Outputs are designed to help route workflows to allow, revise, human_review, or reject.</p></div><div class="card"><h2>2. No forensic or legal determination</h2><p>VeracityAPI outputs are not proof that content is AI-generated, human-authored, true, false, cloned, infringing, safe, illegal, or legally actionable. Do not use the service as the sole basis for academic discipline, employment decisions, credit, housing, insurance, legal claims, identity verification, or other high-stakes determinations.</p></div></section>
<section class="grid"><div class="card"><h2>3. Accounts, API keys, and billing</h2><p>You are responsible for securing your account, sessions, API keys, and integrations. Usage may be billed by request, character unit, or credit balance as shown on the pricing page or account console. Keep keys out of client-side code, public repositories, prompts, and logs.</p></div><div class="card"><h2>4. Acceptable use</h2><p>You may not use VeracityAPI to violate law, abuse rate limits, reverse engineer or attack the service, submit malware or unlawful content, misrepresent outputs as forensic evidence, or build systems that make unsupported high-stakes automated decisions without human review and independent evidence.</p></div></section>
<section class="grid"><div class="card"><h2>5. Content and data handling</h2><p>You retain responsibility for content you submit and must have the rights and permissions needed to process it. VeracityAPI is designed to avoid raw text storage by default when store_content=false and does not store raw image, audio, or video bytes, base64, frames/contact sheets, or full media URLs for media analysis. See the Privacy page for current retention details.</p></div><div class="card"><h2>6. Third-party providers</h2><p>VeracityAPI may use third-party model, infrastructure, payment, email, analytics, or hosting providers to operate the service. Their availability and policies can affect latency, uptime, and processing.</p></div></section>
<section class="grid"><div class="card"><h2>7. Availability and changes</h2><p>The service is provided on a beta/production-evolving basis. Features, prices, models, limits, endpoints, SDKs, MCP tools, and response fields may change. We aim to keep backwards compatibility for documented production endpoints when practical.</p></div><div class="card"><h2>8. Disclaimers and limitation of liability</h2><p>VeracityAPI is provided as-is and as-available, without warranties of accuracy, availability, fitness for a particular purpose, or non-infringement. To the maximum extent permitted by law, VeracityAPI and its operators are not liable for indirect, consequential, special, punitive, or lost-profit damages arising from use of the service. Aggregate liability is limited to fees paid for the service in the prior three months, unless applicable law requires otherwise.</p></div></section>
<section class="card"><h2>9. Termination and contact</h2><p>We may suspend or terminate access for abuse, security risk, non-payment, or violation of these terms. General questions, notices, and deletion/export requests can be sent to <a href="mailto:hello@veracityapi.com">hello@veracityapi.com</a>; security reports to <a href="mailto:security@veracityapi.com">security@veracityapi.com</a>.</p><p><a class="btn primary" href="/privacy">Privacy</a> <a class="btn" href="/pricing">Pricing</a> <a class="btn" href="/account">Account</a></p></section>`, "/terms", "TermsOfService"); }

export function statusHtml(): string { return layout("VeracityAPI Status", "Public status and health checks for VeracityAPI.", `<section class="hero"><div class="eyebrow">Status</div><h1>VeracityAPI is live.</h1><p class="lead">This lightweight status page gives evaluators a public operational surface while a dedicated external uptime page is added. Use <code>/health</code> for machine checks and this page for buyer-facing status context.</p><p><a class="btn primary" href="/health">Check /health</a> <a class="btn" href="/changelog">Changelog</a> <a class="btn" href="/docs">Docs</a></p></section><section class="grid"><div class="card"><h2>API</h2><p><span class="pill">Operational</span></p><p><code>https://api.veracityapi.com/v1/analyze</code> · <code>https://api.veracityapi.com/v1/analyze-video</code></p><p class="hint">Production scoring endpoint for authenticated text, image, audio, private-beta video, and batch workflows.</p></div><div class="card"><h2>Marketing / docs</h2><p><span class="pill">Operational</span></p><p><code>https://veracityapi.com</code></p><p class="hint">Homepage, docs, pricing, changelog, evals, MCP, and discovery documents.</p></div><div class="card"><h2>MCP</h2><p><span class="pill">Operational</span></p><p><code>https://api.veracityapi.com/mcp</code></p><p class="hint">Hosted remote MCP plus local <code>@veracityapi/mcp</code> package.</p></div><div class="card"><h2>Health check</h2><p>Machine-readable status is available at <a href="/health"><code>/health</code></a>. External uptime monitoring should point at that endpoint and the API base.</p></div></section>`, "/status", "WebPage"); }

